// 1. State type (~line 33)
const [overlayPos, setOverlayPos] = useState<{
  top: number;
  right: number; // viewport-right-edge offset — mirrors `.label { right: calc(100% + 1x) }` in CSS
} | null>(null);

// 2. Inside compute() (~line 138)
const r = notch.getBoundingClientRect();
// `right` = distance from viewport right edge to where the label's right edge should land.
// Target: label.right = notch.left − 8px  →  right = viewportW − (notch.left − 8) = viewportW − notch.left + 8.
// This is the fixed-position equivalent of the in-rail `.label { right: calc(100% + var(--portfolio-spacer-1x)) }`.
// No CSS horizontal transform needed; eliminates the -100%-of-own-width reference-box race (FB-156 iter 2).
setOverlayPos({
  top: r.top + r.height / 2,
  right: window.innerWidth - r.left + 8,
});

// 3. Anchor inline style in createPortal (~line 208)
style={
  overlayPos
    ? {
        top: `${overlayPos.top}px`,
        right: `${overlayPos.right}px`,
      }
    : { top: 0, right: 0, visibility: "hidden" }
}
```

